import React, { useState } from 'react';

const FarmerAdd = ({ onBack, onFinish }) => {
  const [step, setStep] = useState(1);
  const [cropName, setCropName] = useState('');
  const [qty, setQty] = useState('');
  const [price, setPrice] = useState('');

  const handleComplete = () => {
    onFinish({ name: cropName, qty: qty, price: `₹${price}` });
    alert("माल यशस्वीरीत्या जमा झाला! (Posted Successfully!)");
  };

  return (
    <div className="min-h-screen bg-white p-6">
      <div className="flex items-center mb-8">
        <button onClick={onBack} className="text-4xl mr-4">⬅️</button>
        <h1 className="text-2xl font-black text-green-800 tracking-tight">STEP {step} OF 3</h1>
      </div>

      {step === 1 && (
        <div className="flex flex-col items-center">
          <p className="text-3xl font-bold mb-6 text-center text-gray-700">What are you selling?<br/>(काय विकणार?)</p>
          <input 
            type="text" 
            value={cropName}
            onChange={(e) => setCropName(e.target.value)}
            placeholder="e.g. Wheat, Rice..." 
            className="w-full p-8 text-4xl rounded-3xl border-4 border-green-600 mb-10 text-center shadow-inner" 
          />
          <button onClick={() => setStep(2)} className="w-full bg-green-600 text-white py-8 rounded-3xl text-3xl font-black shadow-xl border-b-8 border-green-900">
            NEXT (पुढे जा)
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="flex flex-col">
          <p className="text-3xl font-bold mb-6 text-center text-gray-700">How much weight?<br/>(वजन किती?)</p>
          <input 
            type="text" 
            value={qty}
            onChange={(e) => setQty(e.target.value)}
            placeholder="e.g. 50 kg" 
            className="w-full p-8 text-4xl rounded-3xl border-4 border-green-600 mb-10 text-center shadow-inner" 
          />
          <button onClick={() => setStep(3)} className="w-full bg-green-600 text-white py-8 rounded-3xl text-3xl font-black shadow-xl border-b-8 border-green-900">
            NEXT (पुढे जा)
          </button>
        </div>
      )}

      {step === 3 && (
        <div className="flex flex-col">
          <p className="text-3xl font-bold mb-6 text-center text-gray-700">Total Price?<br/>(एकूण किंमत?)</p>
          <input 
            type="number" 
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            placeholder="₹ 0.00" 
            className="w-full p-8 text-5xl rounded-3xl border-4 border-orange-500 mb-10 text-center text-orange-600 font-bold" 
          />
          <button onClick={handleComplete} className="w-full bg-orange-500 text-white py-10 rounded-3xl text-4xl font-black shadow-xl border-b-8 border-orange-800">
            FINISH (पूर्ण झाले)
          </button>
        </div>
      )}
    </div>
  );
};

export default FarmerAdd;
